INSERT INTO branding (id, companyName, logoType, logoIcon, logoImageBase64, themeColor, tagline) VALUES ('default', 'JLC Solutions', 'icon', 'Activity', NULL, 'emerald', 'Empowering Businesses with Reliable, Innovative Technology Services');
INSERT INTO content (id, heroTitle, heroSubtitle, heroBadge, aboutHeader, aboutSubheader, aboutText, aboutText2, aboutMission, aboutVision, aboutCommitments, aboutImageBase64, whyChooseUsText, whyChooseUsPoints, whyChooseUsPromiseTitle, whyChooseUsPromiseDesc, whyChooseUsPromises, whyChooseUsCtaTitle, whyChooseUsCtaDesc, servicesHeader, servicesSubtitle, portfolioHeader, portfolioSubtitle, processHeader, processSubtitle, faqHeader, faqSubtitle, contactHeader, contactSubtitle, contactAddress, contactPhone, contactEmail, contactWorkingHours, contactMapEmbedUrl, bannerImageUrl, facebookUrl, whatsappUrl, viberUrl) VALUES ('default', 'Innovative IT Solutions Crafted for Business Growth', 'At JLC Solutions, we deliver premium software, cloud migration, and secure network infrastructure. Reliable, client-focused engineering to build a stable foundation for your company.', 'Ready for Inquiries', 'Your Strategic Technical Partner', 'Establishing a Strong, Trustworthy Foundation for Future Tech Growth', 'JLC Solutions was founded on the principle that small and medium businesses deserve the same high-caliber technology expertise as multi-million dollar corporations. We act as your strategic technology partner, ensuring your systems are fast, reliable, and secure, so you can focus entirely on your core business.', 'We understand that choosing an IT support and custom development partner is an exercise in trust. That''s why we focus on absolute transparency: we do not inflate our stats, utilize fake client testimonials, or oversell. Instead, we deliver world-class engineering, bulletproof security protocols, and meticulous documentation, ensuring your technology investments support long-term stability and organic growth.', 'To build exceptional, stable, and secure technology foundations for growing businesses through high-quality custom development, cloud engineering, and honest IT guidance.', 'To be the most trusted, reliable, and client-centric boutique IT consulting and software development provider in the industry, powering future-ready business ecosystems.', '[{"id":"ac1","title":"No Hidden Conditions","description":"What we outline in our project scope is exactly what you get, with zero unexpected charges.","iconName":"ShieldAlert"},{"id":"ac2","title":"Meticulous Standards","description":"Every line of code and infrastructure layout follows industry-wide security and performance best practices.","iconName":"Code2"},{"id":"ac3","title":"Direct Communication","description":"You work directly with John Cahilig, the lead systems architect, ensuring no loss of requirements.","iconName":"UserCheck"}]', 'https://images.unsplash.com/photo-1531403009284-440f080d1e12?q=80&w=600&auto=format&fit=crop', 'We do not sell pre-packaged, oversized services. We provide honest, scalable, and highly customized tech services driven by a commitment to reliability, trust, and premium quality.', '[{"id":"w1","title":"Client-Centric Philosophy","description":"We listen first. We design IT solutions around your operational bottlenecks and budget constraints, never suggesting unneeded technologies.","iconName":"Heart"},{"id":"w2","title":"Pristine Code & Quality","description":"We pride ourselves on writing clean, secure, scalable code and setting up well-architected systems that stand the test of time.","iconName":"CheckCircle"},{"id":"w3","title":"Transparent Communication","description":"No technical jargon. We explain what needs to be done, how long it will take, and what it costs with absolute transparency and honesty.","iconName":"MessageSquare"},{"id":"w4","title":"Rigorous Security Standards","description":"Security is not an afterthought. Every solution we build or integrate is hardened against modern security threats from day one.","iconName":"Lock"}]', 'Stable Future Engineering Commitments', 'We formulate technology options centered strictly around integrity, performance specifications, and standard protocol compliance.', '[{"id":"p1","title":"Direct Architect Access","description":"Work directly with John Cahilig, lead developer & system architect, on all project scopes."},{"id":"p2","title":"Transparent Estimates","description":"We write structured project bids with zero hidden fees, licensing surcharges, or ad-hoc costs."},{"id":"p3","title":"Industry Standard Audited","description":"Cabling layouts and backend architectures conform to EIA/TIA and secure server schemas."}]', 'Need a tailor-made technological solution?', 'We are dedicated to building long-term, stable technical systems. No matter how simple or complex your project, we will provide a realistic estimate and deliver standard-compliant, pristine execution.', 'Our Technology Offerings', 'We offer professional, standard-compliant technology engineering and structured IT services for scaling startups and modern workspaces.', 'Portfolio Showcase', 'Explore some of our recently delivered software architectures, structured cabling deployments, and custom IT strategy integrations.', 'Our Operational Lifecycle', 'How we consult, design, implement, and proactively support your startup''s technology ecosystem with absolute clarity.', 'Frequently Asked Questions', 'Have questions about our custom IT strategy compliance, pricing, or remote patch monitoring? Here are quick answers to common queries.', 'Connect With JLC Solutions', 'Have questions about our technology capabilities, security controls, or pricing models? Let us know. We respond to all inquiries within 1 business day.', '128 Zone 3, Poblacion Malay Aklan', '+63 951 913 0636', 'contact@jlcitsolutions.com', 'Monday - Friday: 9:00 AM - 6:00 PM (PHT)', 'https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d124925.14811229547!2d121.86486479471382!3d11.911290456521115!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x33a53f39c65e6973%3A0xa06a04637fde6e83!2sMalay%2C%20Aklan%2C%20Philippines!5e0!3m2!1sen!2sck!4v1782844551858!5m2!1sen!2sck" width="400" height="300" style="border:0;" allowfullscreen="" loading="lazy" referrerpolicy="strict-origin-when-cross-origin', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=1200&auto=format&fit=crop', 'https://facebook.com/jlcitsolutions', 'https://wa.me/639519130636', 'viber://chat?number=639519130636');
INSERT INTO services (id, title, description, iconName, features, position) VALUES ('s4', 'IT Consulting & Technology Strategy', 'Strategic vendor advisory, standard compliance mapping, architecture blueprints, and technology roadmap planning aligned directly with business scaling metrics.', 'Briefcase', '["Digital Transformation Blueprints","IT Infrastructure Compliance Audits","Disaster Recovery Strategy","Capacity Planning & Budgeting"]', 4);
INSERT INTO services (id, title, description, iconName, features, position) VALUES ('s2', 'Managed IT Support', 'Proactive remote monitoring, security patches, backups, and prompt helpdesk troubleshooting to keep your workplace technology running smoothly around the clock.', 'Cpu', '["24/7 Server & System Monitoring","Helpdesk Technical Assistance","Automated Daily Cloud Backups","OS Patching & Application Updates"]', 2);
INSERT INTO services (id, title, description, iconName, features, position) VALUES ('s3', 'Network Infrastructure & Wi-Fi', 'Engineering and layout of reliable high-performance office network systems, firewall security systems, and high-density Wi-Fi networks.', 'Network', '["Router & Layer-3 Switch Setup","Structured Ethernet Cabling & Rack Layout","Secure Site-to-Site VPN Setup","Wi-Fi Heatmaps & Optimization"]', 3);
INSERT INTO services (id, title, description, iconName, features, position) VALUES ('s1', 'Custom Software Development', 'End-to-end development of custom web, mobile, and desktop applications tailored to solve unique business bottlenecks and streamline operations.', 'Code', '["React & Node.js Web Apps","Cross-Platform Mobile Apps","API Integrations & Custom Webhooks","Database Engineering & Modernization"]', 1);
INSERT INTO services (id, title, description, iconName, features, position) VALUES ('s5', 'CCTV Installation', 'Deployment of smart high-definition security camera networks, remote live viewing configurations, secure storage arrays, and network video recorders.', 'Camera', '["IP Camera Deployments","Network Video Recorder Setup","Remote App Live Viewing Integration","Motion Detection Alerts Config"]', 5);
INSERT INTO services (id, title, description, iconName, features, position) VALUES ('s6', 'Cybersecurity Solutions', 'Comprehensive data protection layers, endpoint threat detection, advanced firewall setup, vulnerability scans, and security awareness training.', 'ShieldCheck', '["Threat Vulnerability Scans","Endpoint Protection & Firewalls","IAM Security & Multi-Factor Auth","Employee Cybersecurity Training"]', 6);
INSERT INTO services (id, title, description, iconName, features, position) VALUES ('s7', 'Mobile, Laptop & Desktop Repair', 'Accurate physical diagnostics, hardware component replacements (RAM/SSD upgrades), liquid damage recovery, and operating system restorations.', 'Wrench', '["RAM & High-Speed SSD Upgrades","Laptop Screen & Keyboard Swaps","Data Retrieval & Restoration","OS Clean Restores & Malware Removal"]', 7);
