INSERT INTO faqs (id, question, answer) VALUES ('faq-1', 'What types of businesses do you support?', 'We support small to medium businesses (SMBs), growing startups, as well as residential/individual clients who require reliable IT consulting, custom software, office networking, and cybersecurity systems.');
INSERT INTO faqs (id, question, answer) VALUES ('faq-2', 'Do you offer 24/7 network monitoring?', 'Yes, our Managed IT Services include 24/7 remote monitoring of server health, firewall activity, and secure local area networks to prevent anomalies before they affect operations.');
INSERT INTO faqs (id, question, answer) VALUES ('faq-3', 'How do you handle data privacy and security?', 'Security is at the heart of JLC Solutions. We implement strict multi-factor authentication, endpoint firewalls, automated encrypted backups, and custom Access Control systems configured for high data compliance.');
INSERT INTO faqs (id, question, answer) VALUES ('faq-4', 'Can you build custom APIs and software systems?', 'Absolutely. We design and deliver custom full-stack web architectures, REST APIs, and automated databases matching standard coding specs, ensuring a high-quality product.');
