INSERT INTO project_gallery (id, title, category, imageBase64, description) VALUES ('gal-1', 'HQ Structured Network & Fiber Cabling', 'Network Installation', NULL, 'Designed and installed a high-speed fiber backbone infrastructure and structured network racks for a multi-floor startup headquarters.');
INSERT INTO project_gallery (id, title, category, imageBase64, description) VALUES ('gal-2', 'Custom ERP Logistics & Admin Portal', 'Software Engineering', NULL, 'Developed and launched a custom React & Node.js ERP system featuring real-time warehouse inventory pipelines and invoicing modules.');
INSERT INTO project_gallery (id, title, category, imageBase64, description) VALUES ('gal-3', 'Hybrid Multi-Cloud Database Migration', 'Cloud Infrastructure', NULL, 'Migrated and replicated legacy databases to secure AWS and Google Cloud environments utilizing Kubernetes automated containers.');
INSERT INTO process_steps (id, stepNumber, title, description, iconName) VALUES ('step-1', 1, 'Technical Consultation', 'We meet with your team to review your current infrastructure, pain points, and technical objectives with absolute transparency.', 'MessageSquare');
INSERT INTO process_steps (id, stepNumber, title, description, iconName) VALUES ('step-2', 2, 'Architect & Design', 'Our lead consultant builds a comprehensive solution design, outlining exact dependencies, pricing models, and hardware specifications.', 'FileText');
INSERT INTO process_steps (id, stepNumber, title, description, iconName) VALUES ('step-3', 3, 'Secure Implementation', 'We build your codebase, deploy servers, or run network cabling according to high industry standards and security compliance.', 'Cpu');
INSERT INTO process_steps (id, stepNumber, title, description, iconName) VALUES ('step-4', 4, 'Testing & Delivery', 'Every endpoint and capability undergoes thorough quality assurance, vulnerability scans, and load testing prior to operational handover.', 'ShieldCheck');
INSERT INTO process_steps (id, stepNumber, title, description, iconName) VALUES ('step-5', 5, 'Ongoing Management', 'We provide active patch monitoring, automated backups, and instant remote technical assistance to keep your startup scaling.', 'Activity');
INSERT INTO roadmap_steps (id, timeline, title, description, status) VALUES ('rm-1', 'Q3 2026', 'Service Catalog Expansion', 'Adding advanced smart office automation and custom IoT integration services to our dynamic capabilities.', 'in-progress');
INSERT INTO roadmap_steps (id, timeline, title, description, status) VALUES ('rm-2', 'Q4 2026', 'Security Compliance Auditing', 'Obtaining full SOC2 Type II certification to elevate enterprise confidence and client trust.', 'planned');
INSERT INTO roadmap_steps (id, timeline, title, description, status) VALUES ('rm-3', 'Q1 2027', 'Interactive Client Portal', 'Launching a secure self-service portal for active inquiries, real-time ticket tracking, and contract invoices.', 'planned');
